// The Pi AI HAT stands in here: the "camera" sees who is at the cabinet.
// Change `present` to test other scenarios: ['Kian'] ['Nika'] ['Reza'] ['unknown'] []
const chat = $input.first().json;
const userText = (chat.chatInput || chat.message || chat.text || '').toString();
const sessionId = (chat.sessionId || chat.sessionID || 'default').toString();
const present = ['Kian'];        // who the camera recognises
const language = 'en';           // cabinet language: 'en' or 'de' (German default on the real Pi)
const runningGame = null;        // no game on the screen in this demo

// The real arcade catalogue (brain/scenarios.py)
const GAMES = [
  {title:'Track & Field', console:'Atari', genre:'sports',     max:1, quick:false},
  {title:'River Raid',    console:'Atari', genre:'shooter',    max:1, quick:false},
  {title:'Pong',          console:'Atari', genre:'sports',     max:2, quick:true },
  {title:'Tetris',        console:'NES',   genre:'puzzle',     max:1, quick:true },
  {title:'Contra',        console:'NES',   genre:'shooter',    max:2, quick:false},
  {title:'Super Mario World', console:'SNES', genre:'platformer', max:1, quick:false},
  {title:'Street Fighter II', console:'SNES', genre:'fighting',   max:2, quick:false},
  {title:'Mario Kart 64', console:'N64',   genre:'racing',     max:2, quick:true },
];
const gameList = GAMES.map(g=>g.title).join(', ');

// Possibility map (brain/agent.py): a running game "owns" the screen, so some
// intents aren't even offered to the model while one is on.
const INTENT_NAMES = ['play_game','stop_game','list_games','recommend','remember',
  'create_profile','delete_profile','set_privacy','monitor','switch_language',
  'get_context','goodbye','other'];
const allowed = runningGame
  ? INTENT_NAMES.filter(n => !['create_profile','delete_profile'].includes(n))
  : INTENT_NAMES;

// The REAL intent system prompt + bilingual few-shots (brain/agent.py). Constant,
// so llama.cpp caches its prefill between turns on the Pi.
const EXAMPLES = `"let's play pong" -> {"intent":"play_game","title":"Pong"}
"lass uns tetris spielen" -> {"intent":"play_game","title":"Tetris"}
"put on track and field" -> {"intent":"play_game","title":"Track & Field"}
"stop the game" -> {"intent":"stop_game"}
"ich bin fertig" -> {"intent":"stop_game"}
"what can I play?" -> {"intent":"list_games"}
"was soll ich spielen?" -> {"intent":"recommend"}
"I want something in sport" -> {"intent":"recommend","genre":"sports"}
"ich moechte ein rennspiel" -> {"intent":"recommend","genre":"racing"}
"I wanna play something from mario" -> {"intent":"recommend","query":"Mario"}
"not that one, something else" -> {"intent":"recommend"}
"remember I only play after 5pm" -> {"intent":"remember","note":"only plays after 5pm"}
"save my profile, I'm Sam" -> {"intent":"create_profile","name":"Sam"}
"create a profile for me" -> {"intent":"create_profile"}
"delete my profile" -> {"intent":"delete_profile"}
"turn off the mic and camera every night from 8pm to 9am" -> {"intent":"set_privacy","start":"20:00","end":"09:00"}
"turn off the screen" -> {"intent":"monitor","on":false}
"speak English please" -> {"intent":"switch_language","language":"en"}
"sprich Deutsch" -> {"intent":"switch_language","language":"de"}
"what time is it?" -> {"intent":"get_context"}
"what is the cpu temperature?" -> {"intent":"get_context"}
"how long have I been playing?" -> {"intent":"get_context"}
"bye" -> {"intent":"goodbye"}
"tschuess" -> {"intent":"goodbye"}`;

const SYSTEM = `You label what a person at an arcade wants, as JSON only (no prose). `
  + `The person may speak English or German. Known games: ${gameList}.\n`
  + `Return JSON with intent plus only the fields that apply (title, genre, query, `
  + `note, name, start, end, on, language). Convert times to 24h HH:MM. Only include `
  + `name if the person actually said a name. If truly unrelated, use {"intent":"other"}.\n`
  + `Examples:\n${EXAMPLES}`;

// Ollama structured-output schema: decoding is constrained to this, so the model
// physically cannot invent an intent or answer in prose.
const SCHEMA = {
  type:'object',
  properties:{
    intent:{type:'string', enum: INTENT_NAMES},
    title:{type:'string'}, genre:{type:'string'}, query:{type:'string'},
    note:{type:'string'}, name:{type:'string'},
    start:{type:'string'}, end:{type:'string'}, on:{type:'boolean'},
    language:{type:'string', enum:['en','de']},
  },
  required:['intent'],
};

const intentBody = {
  model: 'qwen2.5:7b-instruct', stream:false, keep_alive:-1,
  options:{ temperature:0.1, num_predict:48 },
  format: SCHEMA,
  messages:[
    {role:'system', content: SYSTEM},
    {role:'user',   content: `Doable right now: ${allowed.join(', ')}.\nThe person said: "${userText}"`},
  ],
};

return [{ json: { userText, sessionId, present, language, runningGame, games: GAMES, allowed, intentBody } }];

// STEP 2 — CODE runs the action deterministically and OWNS access control.
// The model only labelled the request; who-may-do-what is decided here.
const ctx = $('AI HAT Context').first().json;
const raw = $input.first().json;

let slots;
try { slots = JSON.parse(raw.message.content); }
catch (e) { slots = { intent: 'other' }; }
// A small model occasionally reaches past the menu it was given -> coerce.
if (!ctx.allowed.includes(slots.intent)) slots.intent = 'other';

const GAMES = ctx.games;
const present = ctx.present;
let language = ctx.language;

// Demo memory (brain/scenarios.py): remaining screen-time + minutes played today.
const BUDGET = { kian: 45, nika: 10 };
const PLAYED = { kian: 110, nika: 45 };
// Never let a 3B hand over a pronoun as a person's name (brain/agent.py guard).
const PRONOUNS = ['me','myself','i','you','guest','unknown','unspecified','someone','somebody','user'];

// ---- SESSION MEMORY (mirrors the Session in brain/app.py) ----------------
// Persists across turns for the SAME chat session. NOTE: n8n only saves static
// data for ACTIVE (production/hosted-chat) executions, not the editor's test
// chat — so run this from the hosted chat URL for multi-turn memory.
const store = $getWorkflowStaticData('global');
store.sessions = store.sessions || {};
const sid = ctx.sessionId || 'default';
const sess = store.sessions[sid] || { last_suggested: null, running_game: null, rejected: [] };
const who = (present[0] || '').toLowerCase();

// Acceptance / rejection of a pending offer is decided in CODE, not by the model
// (brain/agent.py _ACCEPTANCES). "sure" after "How about Pong?" must LAUNCH it.
const norm = (ctx.userText || '').toLowerCase().replace(/[^a-zà-ÿ ]/g,'').trim();
const ACCEPT = ['yes','yeah','yep','yup','sure','ok','okay','okey','alright','all right','fine',
  'why not','go for it','lets go','let s go','lets do it','let s do it','do it','sounds good',
  'that one','thats the one','sure thing','ja','klar','mach das','los','los gehts'];
const REJECT = ['no','nope','nah','not that','not that one','something else','anything else',
  'next','another','nein','nee','was anderes','etwas anderes'];
const hit = (list) => list.includes(norm) || list.some(w => w.length > 3 && norm.includes(w));

let name = slots.intent;
if (sess.last_suggested && !sess.running_game &&
    ['other','goodbye','play_game','recommend'].includes(name)) {
  if (hit(ACCEPT))      { slots = { intent:'play_game', title: sess.last_suggested, _accepted:true }; name='play_game'; }
  else if (hit(REJECT)) { slots = { intent:'recommend', _rejected:true };                             name='recommend'; }
}

let phraseKind = name;
let facts = {};
const actions = [];

function pickGame(genre, query) {
  let pool = GAMES.slice();
  if (genre) pool = pool.filter(g => g.genre === genre);
  if (query) { const q=query.toLowerCase(); const h=GAMES.filter(g=>g.title.toLowerCase().includes(q)); if (h.length) pool=h; }
  pool = pool.filter(g => !sess.rejected.includes(g.title));
  if (!pool.length) pool = GAMES.filter(g => !sess.rejected.includes(g.title));
  if (!pool.length) pool = GAMES.slice();
  const budget = BUDGET[who];
  if (budget != null && budget <= 15) { const quick = pool.filter(g=>g.quick); if (quick.length) pool=quick; }
  return pool[0];
}
function launch(title) {
  const t = (title || '').toLowerCase();
  const g = t && (GAMES.find(x => x.title.toLowerCase() === t) ||
                  GAMES.find(x => x.title.toLowerCase().includes(t)));
  if (g) { sess.running_game=g.title; sess.last_suggested=null; phraseKind='play_game';
           facts={ launched:g.title, players:g.max, confirmed: !!slots._accepted };
           actions.push({ tool:'launch_game', args:{ title:g.title } }); }
  else   { phraseKind='not_found'; facts={ asked: title || '' }; }
}

switch (name) {
  case 'list_games':
    facts = { games: GAMES.map(g => g.title) };
    break;
  case 'recommend': {
    // Naming a specific game IS the choice — launch it, don't re-offer it.
    if (slots.query) { const g = GAMES.find(x => x.title.toLowerCase() === slots.query.toLowerCase());
                       if (g) { launch(g.title); break; } }
    if (slots._rejected && sess.last_suggested && !sess.rejected.includes(sess.last_suggested))
      sess.rejected.push(sess.last_suggested);
    const pick = pickGame(slots.genre, slots.query);
    sess.last_suggested = pick.title;
    facts = { suggestion: pick.title, genre: pick.genre, players: pick.max,
              lowTime: BUDGET[who] != null && BUDGET[who] <= 15, budget: BUDGET[who], again: !!slots._rejected };
    actions.push({ tool: 'suggest_game', args: { title: pick.title } });
    break;
  }
  case 'play_game':
    launch(slots.title || '');
    break;
  case 'stop_game': {
    const closed = sess.running_game; sess.running_game = null;
    facts = { stopped: closed || '' };
    actions.push({ tool:'close_game', args:{} });
    break;
  }
  case 'get_context': {
    const now = new Date();
    facts = { time: now.toTimeString().slice(0,5), cpu_temp_c: 54.5, present,
              played_min: PLAYED[who] || 0, budget_left_min: BUDGET[who], now_playing: sess.running_game };
    break;
  }
  case 'remember':
    facts = { note: slots.note || '' };
    actions.push({ tool:'remember', args:{ note: slots.note || '' } });
    break;
  case 'create_profile': {
    const nm = (slots.name || '').trim();
    if (!nm || PRONOUNS.includes(nm.toLowerCase())) { phraseKind='ask_name'; facts={}; }
    else { phraseKind='create_profile'; facts={ name:nm };
           actions.push({ tool:'create_profile', args:{ name:nm } }); }
    break;
  }
  case 'delete_profile': facts = { name: present[0] || '' }; break;
  case 'set_privacy':
    facts = { start: slots.start || '', end: slots.end || '' };
    actions.push({ tool:'set_privacy', args:{ start:slots.start, end:slots.end } });
    break;
  case 'monitor':
    facts = { on: !!slots.on };
    actions.push({ tool:'set_monitor', args:{ on: !!slots.on } });
    break;
  case 'switch_language':
    language = slots.language || language; phraseKind='switch_language'; facts={ language };
    break;
  case 'goodbye':   facts = {}; break;
  default:          phraseKind = 'other'; facts = {};
}

// Persist the session (saved on ACTIVE/hosted executions).
store.sessions[sid] = sess;

// STEP 3 request — phrase the outcome as Arc would say it (EN/DE, <=2 sentences).
const PH_SYS = `You are Arc, a warm, playful companion living in a retro arcade cabinet. `
  + `Speak in ${language === 'de' ? 'German' : 'English'}. Reply in at most two short spoken `
  + `sentences, no markdown, no lists. Base your reply ONLY on the facts given — never invent `
  + `games, names, times or numbers. You MUST state every concrete value present in facts `
  + `(the time, minutes played, minutes left, temperature, or game title). `
  + `If the outcome is "ask_name", warmly ask what their name is.`;
const phraseBody = {
  model: 'qwen2.5:7b-instruct', stream:false, keep_alive:-1,
  options:{ temperature:0.3, num_predict:80 },
  messages:[
    {role:'system', content: PH_SYS},
    {role:'user',   content: JSON.stringify({ outcome: phraseKind, who_is_present: present, facts })},
  ],
};

return [{ json: { intent: name, understood: slots, phraseKind, facts, actions,
                  language, present, sessionId: sid, memory: sess,
                  userText: ctx.userText, phraseBody } }];

const ex = $('2 · Execute Intent (code owns access control)').first().json;
const raw = $input.first().json;
const line = (raw && raw.message && raw.message.content ? raw.message.content : '').trim();
return [{ json: {
  output: line,                 // what the chat shows (and what Piper TTS would speak on the Pi)
  intent: ex.intent,            // what step 1 understood
  tools_called: ex.actions,     // what step 2 deterministically did
  who_is_present: ex.present,
  understood: ex.understood,
} }];
